SELECT [Item Unit of Measure].*
FROM [Item Unit of Measure]
WHERE ((([Item Unit of Measure].[Item No_]) Like "7FARIA01/LEA%" Or ([Item Unit of Measure].[Item No_]) Like "7FWOSUONO01/LEA%" Or ([Item Unit of Measure].[Item No_]) Like "YLE14/TEXTURED%" Or ([Item Unit of Measure].[Item No_]) Like "DLY32/NET%" Or ([Item Unit of Measure].[Item No_]) Like "JNE04/CROSTA-VIT%" Or ([Item Unit of Measure].[Item No_]) Like "7FMURRAY01/LEA%" Or ([Item Unit of Measure].[Item No_]) Like "7SWOBOWLING/LEA%" Or ([Item Unit of Measure].[Item No_]) Like "8SMADISON01/MES%" Or ([Item Unit of Measure].[Item No_]) Like "8SMASTER01/LEA%"));

